## 1) Пример конфигурации Nginx (reverse proxy + SSL + заголовки)
Ниже пример `nginx.conf` (или можно использовать как фрагмент `server`-конфига в `/etc/nginx/sites-available/...` — но ты просил именно `nginx.conf`, поэтому дам целиком-скелет). Главное: блок `server` для `api.example.com` и проксирование на `127.0.0.1:8080`, плюс корректные заголовки.

> ⚠️ Пути к сертификатам должны совпадать с тем, как Certbot их разместил. Обычно это `/etc/letsencrypt/live/<domain>/fullchain.pem` и `privkey.pem`.

```nginx
# /etc/nginx/nginx.conf (пример)
user www-data;
worker_processes auto;
pid /run/nginx.pid;

events {
    worker_connections 1024;
}

http {
    include       /etc/nginx/mime.types;
    default_type  application/octet-stream;

    log_format main '$remote_addr - $remote_user [$time_local] '
                    '"$request" $status $body_bytes_sent '
                    '"$http_referer" "$http_user_agent"';

    access_log /var/log/nginx/access.log main;
    error_log  /var/log/nginx/error.log;

    sendfile on;
    keepalive_timeout 65;

    # --- ВАЖНО: корректные заголовки для прокси ---
    # (можно вынести в отдельный location/proxy params, но сделаем прямо)
    upstream internal_api {
        server 127.0.0.1:8080;
    }

    server {
        listen 80;
        server_name api.example.com;

        # Для Certbot удобнее дать HTTP-ответ, чтобы проходил auth challenge
        location /.well-known/acme-challenge/ {
            root /var/www/html;
        }

        # остальной трафик на HTTPS
        location / {
            return 301 https://$host$request_uri;
        }
    }

    server {
        listen 443 ssl http2;
        server_name api.example.com;

        # Пути к сертификатам Let's Encrypt (typical для certbot)
        ssl_certificate     /etc/letsencrypt/live/api.example.com/fullchain.pem;
        ssl_certificate_key /etc/letsencrypt/live/api.example.com/privkey.pem;

        # Рекомендуемые настройки SSL (можно оставить дефолт certbot/или ужесточить отдельно)
        ssl_session_cache shared:SSL:10m;
        ssl_session_timeout 10m;

        ssl_protocols TLSv1.2 TLSv1.3;
        ssl_prefer_server_ciphers off;

        # --- Reverse proxy ---
        location / {
            proxy_pass http://internal_api;

            # Передача IP клиента
            proxy_set_header X-Real-IP $remote_addr;
            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;

            # Передача схемы (http/https)
            proxy_set_header X-Forwarded-Proto $scheme;

            # Обычно полезно для корректной работы заголовков/аптайма
            proxy_http_version 1.1;
            proxy_set_header Host $host;

            # Если у тебя websocket — добавь (не обязательно, но часто нужно)
            proxy_set_header Upgrade $http_upgrade;
            proxy_set_header Connection $connection_upgrade;

            # В некоторых конфигурациях нужно определить $connection_upgrade:
            # (внутри http можно добавить map, либо можно убрать, если не нужно)
        }
    }

    # Чтобы $connection_upgrade корректно работала (для websocket)
    # Добавь в http-блок (если используешь Upgrade/Connection как выше):
    map $http_upgrade $connection_upgrade {
        default upgrade;
        ''      close;
    }
}
```

### Проверка конфигурации
```bash
nginx -t
sudo systemctl reload nginx
```

